+        let reclaimable_summary = plan
+            .shard_disposition_summaries
+            .get(&LexicalCleanupDisposition::SupersededReclaimable)
+            .expect("superseded reclaimable shard summary");
+        assert_eq!(reclaimable_summary.shard_count, 1);
